const accordeon=document.querySelectorAll(".accordeon-section"),burgerMenu=document.querySelector(".menu-btn"),wrapper=document.querySelector(".wrapper-burger-menu"),menuBox=document.querySelector(".menu-section-mob"),headerMenu=document.querySelectorAll(".header-nav-list"),iconMenu=document.querySelector(".menu-icon");iconMenu&&iconMenu.addEventListener("click",(function(e){iconMenu.classList.toggle("active"),wrapper.classList.toggle("active-wrapper"),menuBox.classList.toggle("active-block"),document.body.style.overflow="hidden"}));const accordeonClick=function(e){accordeon.forEach((function(e){e.querySelector(".accordeon-panel").style.maxHeight="0px"}));let c=e.target.closest(".accordeon-section").querySelector(".accordeon-panel").scrollHeight;e.target.closest(".accordeon-section").querySelector(".accordeon-panel").style.maxHeight=c+"px",menuBox.style.minHeight=790+c+"px"};accordeon.forEach((function(e){e.addEventListener("click",accordeonClick)}));